//! Unified block building with tip-maximizing sort and sequencing rights.
//!
//! This module provides the refactored block building logic that:
//! 1. Collects all tip-paying transactions from multiple sources
//! 2. Sorts by effective tip (tip-maximizing)
//! 3. Applies sequencing rights bucketing

mod tests {
    use super::*;

    #[test]
    fn test_can_fit_in_block() {
        assert!(can_fit_in_block(100, 0, 1000));
        assert!(can_fit_in_block(100, 900, 1000));
        assert!(!can_fit_in_block(100, 901, 1000));
    }

    #[test]
    fn test_extract_delivery_tip_short_input() {
        let short_input = Bytes::from_static(&[0u8; 64]);
        assert_eq!(extract_delivery_effective_tip(&short_input, 100), 0);
    }
